using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now writes entry names as UTF-8
        // (sets the EFS flag). The legacy Java consumer expects Shift-JIS, so
        // specify the encoding explicitly to preserve the old behaviour.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create);
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        archive.CreateEntry("レポート/月次.csv", CompressionLevel.Optimal, shiftJis);
        archive.CreateEntry("données/résumé.txt", CompressionLevel.Optimal, shiftJis);
    }
}

